create table dirkspzm32.isi_res_leistung_cfg (
    res_l_cfg_id     number(*, 0) not null enable,
    sid              varchar2(2 char) not null enable,
    firma_nr         number(2, 0) not null enable,
    res_id           number(*, 0) not null enable,
    param_name       varchar2(20 char) not null enable,
    param_menge      number(*, 3),
    param_menge_einh varchar2(20 char),
    param_zeit       number(*, 12),
    param_zeit_einh  varchar2(20 char),
    param_erhebung   varchar2(1 char)
);

alter table dirkspzm32.isi_res_leistung_cfg
    add constraint ix_isi_res_leistung_cfg unique ( res_id,
                                                    param_name )
        using index enable;

alter table dirkspzm32.isi_res_leistung_cfg
    add constraint pk_isi_res_leistung_cfg primary key ( res_l_cfg_id )
        using index enable;


